formatting.json_schema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "required": ["rankedIds"],
  "properties": {
    "rankedIds": {
      "type": "array",
      "description": "Record IDs in order of relevance, most relevant first",
      "items": {
        "type": "string"
      }
    }
  }
}
